```class Solution {
public:
    int longestDecomposition(string text) {
        int k = 1;
        for (int i = 1; i < text.length(); i++) {
            for (int j = i + 1; j <= text.length(); j++) {
                if (text.substr(i, j - i) == text.substr(i, j - i)) {
                    k = max(k, j - i + 1);
                }
            }
        }
        return k;
    }
};
